INSERT INTO `sys_oper_log` VALUES ('514', '我的成果-修改', '2', 'com.edu.achievement.controller.EduAchievementController.teacherEdit()', 'PUT', '1', 'teacher01', null, '/achievement/teacherUpdateAchievement', '127.0.0.1', '', '{\"achievementId\":100,\"category\":\"4\",\"collegeId\":111,\"content\":\"本项目针对当前高校软件工程专业教学中存在的\\\"重理论、轻实践\\\"问题，创新性地引入了基于Spring Cloud微服务架构的教学模式。通过构建一个由14个独立微服务组成的教学实验平台，学生在项目实训中能够直接参与真实的企业级系统开发，涵盖服务注册与发现、配置中心、API网关、负载均衡、熔断降级等核心技术栈。项目自2024年9月启动以来，已覆盖3个年级、累计600余名学生，学生的工程项目实践能力显著提升。核心创新点包括：（1）将企业级微服务技术栈融入课堂教学；（2）设计分层递进的实训任务体系；（3）建立校企联动的成果评价机制。学生在全国大学生服务外包创新创业大赛中获国家级二等奖1项、省级一等奖2项。\",\"fileUrl\":\"http://127.0.0.1:9000/edu-achievement/2026/03/03/张鹏展简历_20260303161514A007.pdf\",\"level\":\"1\",\"params\":{},\"status\":\"0\",\"teacherId\":200,\"title\":\"基于微服务架构的软件工程专业教学改革与实践\",\"updateBy\":\"teacher01\",\"updateTime\":\"2026-04-28 13:36:49\"} ', '{\"msg\":\"操作成功\",\"code\":200}', '0', null, '2026-04-28 13:36:49', '53');
INSERT INTO `sys_oper_log` VALUES ('515', 'School Audit', '2', 'com.edu.achievement.controller.EduAuditRecordController.schoolHandle()', 'POST', '1', 'schoolAudit', null, '/audit/school/handle', '127.0.0.1', '', '{\"achievementId\":111,\"achievementTitle\":\"计算机类课程\\\"竞赛驱动\\\"教学模式研究\",\"auditLevel\":\"2\",\"auditOpinion\":\"123\",\"auditResult\":\"1\",\"auditorId\":103,\"auditorName\":\"schoolAudit\",\"createTime\":\"2026-04-28 14:51:43\",\"params\":{},\"recordId\":32} ', '{\"msg\":\"操作成功\",\"code\":200}', '0', null, '2026-04-28 14:51:44', '44');
